// Get synthesized data
const synthesizeOutput = $input.item.json;
const prepareData = $node["Prepare Data"].json;

// Get the text output (handle both Claude and Gemini format)
let resumeText = '';
if (synthesizeOutput.output && synthesizeOutput.output[0]) {
  resumeText = synthesizeOutput.output[0].content[0].text;
} else if (synthesizeOutput.content) {
  resumeText = synthesizeOutput.content[0].text;
}

// Get template selection
const selectedTemplate = prepareData.selectedTemplate || 'modern-minimalist';
const photoBase64 = prepareData.photoBase64 || '';

// Parse the resume text
const lines = resumeText.split('\n').map(l => l.trim()).filter(l => l);

// Extract header info
let name = '', title = '', email = '', phone = '', location = '', linkedin = '';
lines.forEach(line => {
  if (line.startsWith('NAME:')) name = line.replace('NAME:', '').trim();
  if (line.startsWith('TITLE:')) title = line.replace('TITLE:', '').trim();
  if (line.startsWith('EMAIL:')) email = line.replace('EMAIL:', '').trim();
  if (line.startsWith('PHONE:')) phone = line.replace('PHONE:', '').trim();
  if (line.startsWith('LOCATION:')) location = line.replace('LOCATION:', '').trim();
  if (line.startsWith('LINKEDIN:')) linkedin = line.replace('LINKEDIN:', '').trim();
});

// Extract sections
const getSection = (startMarker, endMarker) => {
  const startIdx = lines.findIndex(l => l.startsWith(startMarker));
  const endIdx = endMarker ? lines.findIndex((l, i) => i > startIdx && l.startsWith(endMarker)) : lines.length;
  return startIdx >= 0 ? lines.slice(startIdx + 1, endIdx > startIdx ? endIdx : lines.length) : [];
};

const workLines = getSection('WORK EXPERIENCE:', 'EDUCATION:');
const eduLines = getSection('EDUCATION:', 'SKILLS:');
const skillLines = getSection('SKILLS:', 'PROJECTS:');
const projectLines = getSection('PROJECTS:', 'CERTIFICATIONS:');
const certLines = getSection('CERTIFICATIONS:', null);

// Parse work experience
let workHTML = '';
let currentJob = null;
workLines.forEach(line => {
  if (line.startsWith('Company:')) {
    if (currentJob) workHTML += `<li>${currentJob.bullets.join('</li><li>')}</li></ul></div>`;
    const parts = line.replace('Company:', '').split('|');
    currentJob = { company: parts[0].trim(), duration: parts[1] ? parts[1].replace('Duration:', '').trim() : '', title: '', bullets: [] };
  } else if (line.startsWith('Title:')) {
    currentJob.title = line.replace('Title:', '').trim();
    workHTML += `<div class="experience-item"><div class="job-header"><div><span class="job-title">${currentJob.title}</span><span class="company-name"> | ${currentJob.company}</span></div><span class="job-duration">${currentJob.duration}</span></div><ul>`;
  } else if (line.startsWith('-')) {
    currentJob.bullets.push(line.substring(1).trim());
  }
});
if (currentJob) workHTML += `<li>${currentJob.bullets.join('</li><li>')}</li></ul></div>`;

// Parse education
let eduHTML = '';
eduLines.forEach(line => {
  if (line.includes('|')) {
    const parts = line.split('|').map(p => p.trim());
    eduHTML += `<div class="education-item"><span class="degree">${parts[0]}</span><span class="institution"> | ${parts[1]}</span><div class="education-details">${parts[2] || ''}</div></div>`;
  }
});

// Parse skills
let skillHTML = '<div class="skills-list">';
skillLines.forEach(line => {
  if (line.includes(':')) {
    const [category, skills] = line.split(':');
    skillHTML += `<div class="skill-category"><strong>${category.trim()}:</strong> ${skills.trim()}</div>`;
  }
});
skillHTML += '</div>';

// Parse projects
let projectHTML = '';
let currentProject = null;
projectLines.forEach(line => {
  if (line.includes('Technologies:')) {
    if (currentProject) projectHTML += `<li>${currentProject.bullets.join('</li><li>')}</li></ul></div>`;
    const parts = line.split('|');
    currentProject = { name: parts[0].trim(), tech: parts[1].replace('Technologies:', '').trim(), bullets: [] };
    projectHTML += `<div class="project-item"><div class="project-name">${currentProject.name}</div><div class="project-tech">Technologies: ${currentProject.tech}</div><ul>`;
  } else if (line.startsWith('-')) {
    if (currentProject) currentProject.bullets.push(line.substring(1).trim());
  }
});
if (currentProject) projectHTML += `<li>${currentProject.bullets.join('</li><li>')}</li></ul></div>`;

// Parse certifications
let certHTML = '<div class="skills-list">';
certLines.forEach(line => {
  if (line.startsWith('-') && !line.includes('None')) {
    certHTML += `<div class="skill-category">${line.substring(1).trim()}</div>`;
  }
});
certHTML += '</div>';

// Generate final HTML based on template
let finalResume = '';

if (selectedTemplate === 'modern-minimalist') {
  // TWO-COLUMN LAYOUT WITH DARK SIDEBAR (LEFT TEMPLATE)
  finalResume = `<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<style>
@page { margin: 0; size: A4; }
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: 'Segoe UI', Arial, sans-serif; font-size: 10pt; line-height: 1.5; color: #333; }
.container { display: flex; min-height: 100vh; }
.sidebar { width: 35%; background: linear-gradient(180deg, #2c5f6f 0%, #1e4854 100%); color: #fff; padding: 40px 30px; }
.photo-container { text-align: center; margin-bottom: 30px; }
.photo { width: 160px; height: 160px; border-radius: 50%; border: 5px solid #fff; object-fit: cover; }
.sidebar-section { margin-bottom: 30px; }
.sidebar-header { font-size: 13pt; font-weight: 700; text-transform: uppercase; margin-bottom: 12px; border-bottom: 2px solid #fff; padding-bottom: 6px; letter-spacing: 1px; }
.sidebar-content { font-size: 9.5pt; line-height: 1.7; }
.contact-item { margin-bottom: 10px; word-break: break-word; }
.main-content { width: 65%; padding: 40px 45px; background: #fff; }
.main-header { margin-bottom: 25px; padding-bottom: 15px; }
.main-name { font-size: 32pt; font-weight: 700; color: #2c5f6f; letter-spacing: 1px; text-transform: uppercase; }
.main-title { font-size: 13pt; color: #555; margin-top: 8px; }
.main-section { margin-bottom: 25px; }
.main-section-header { font-size: 14pt; font-weight: 700; color: #2c5f6f; text-transform: uppercase; margin-bottom: 12px; border-bottom: 2px solid #2c5f6f; padding-bottom: 5px; letter-spacing: 1px; }
.experience-item { margin-bottom: 18px; }
.job-header { display: flex; justify-content: space-between; margin-bottom: 8px; }
.job-title { font-weight: 700; font-size: 11.5pt; color: #2c5f6f; }
.company-name { font-weight: 600; color: #555; }
.job-duration { font-size: 9pt; color: #666; font-style: italic; }
ul { margin: 6px 0 0 20px; padding: 0; }
li { margin-bottom: 5px; line-height: 1.6; }
.education-item { margin-bottom: 12px; color: #fff; }
.degree { font-weight: 700; font-size: 10.5pt; }
.institution { color: #ddd; font-size: 9.5pt; }
.education-details { color: #ccc; font-size: 9pt; margin-top: 4px; }
.skill-category { margin-bottom: 8px; }
.skills-list .skill-category { color: #fff; }
.project-item { margin-bottom: 16px; }
.project-name { font-weight: 700; font-size: 11pt; margin-bottom: 3px; }
.project-tech { color: #666; font-size: 9.5pt; font-style: italic; margin-bottom: 6px; }
</style>
</head>
<body>
<div class="container">
  <div class="sidebar">
    ${photoBase64 ? `<div class="photo-container"><img src="${photoBase64}" class="photo" alt="Profile Photo" /></div>` : ''}
    <div class="sidebar-section">
      <div class="sidebar-header">CONTACT</div>
      <div class="sidebar-content">
        <div class="contact-item">📧 ${email}</div>
        <div class="contact-item">📞 ${phone}</div>
        <div class="contact-item">📍 ${location}</div>
        <div class="contact-item">🔗 ${linkedin}</div>
      </div>
    </div>
    <div class="sidebar-section">
      <div class="sidebar-header">EDUCATION</div>
      <div class="sidebar-content">${eduHTML}</div>
    </div>
    <div class="sidebar-section">
      <div class="sidebar-header">SKILLS</div>
      <div class="sidebar-content">${skillHTML}</div>
    </div>
    ${certHTML.includes('skill-category') ? `<div class="sidebar-section"><div class="sidebar-header">CERTIFICATIONS</div><div class="sidebar-content">${certHTML}</div></div>` : ''}
  </div>
  <div class="main-content">
    <div class="main-header">
      <div class="main-name">${name}</div>
      <div class="main-title">${title}</div>
    </div>
    <div class="main-section">
      <div class="main-section-header">WORK EXPERIENCE</div>
      ${workHTML}
    </div>
    ${projectHTML ? `<div class="main-section"><div class="main-section-header">PROJECTS</div>${projectHTML}</div>` : ''}
  </div>
</div>
</body>
</html>`;
} else {
  // SINGLE COLUMN LAYOUT (RIGHT TEMPLATE - executive-professional)
  finalResume = `<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<style>
@page { margin: 0.75in; size: A4; }
body { font-family: Arial, sans-serif; font-size: 10.5pt; line-height: 1.5; color: #333; margin: 0; padding: 20px; }
.header { text-align: center; margin-bottom: 20px; border-bottom: 2px solid #333; padding-bottom: 15px; }
.name { font-size: 28pt; font-weight: 700; color: #000; margin-bottom: 5px; }
.title { font-size: 12pt; color: #666; margin-bottom: 10px; }
.contact-info { font-size: 9.5pt; color: #555; margin-top: 8px; }
.section-header { font-size: 13pt; font-weight: 700; text-transform: uppercase; margin-top: 20px; margin-bottom: 12px; border-bottom: 2px solid #333; padding-bottom: 5px; letter-spacing: 1px; }
.experience-item, .project-item { margin-bottom: 16px; }
.job-header { display: flex; justify-content: space-between; margin-bottom: 6px; }
.job-title { font-weight: 700; font-size: 11pt; }
.company-name { font-weight: 600; color: #555; }
.job-duration { font-style: italic; color: #666; font-size: 9.5pt; }
ul { margin: 8px 0 0 20px; padding: 0; }
li { margin-bottom: 4px; line-height: 1.6; }
.skills-list { margin-top: 10px; }
.skill-category { margin-bottom: 8px; line-height: 1.6; }
.education-item { margin-bottom: 12px; }
.degree { font-weight: 700; font-size: 11pt; }
.institution { color: #555; }
.education-details { color: #666; font-size: 9.5pt; margin-top: 2px; }
.project-name { font-weight: 700; font-size: 11pt; margin-bottom: 3px; }
.project-tech { color: #666; font-size: 9.5pt; font-style: italic; margin-bottom: 6px; }
strong { font-weight: 700; color: #000; }
</style>
</head>
<body>
<div class="header">
  <div class="name">${name}</div>
  <div class="title">${title}</div>
  <div class="contact-info">📧 ${email} | 📞 ${phone} | 📍 ${location} | 🔗 ${linkedin}</div>
</div>
<div class="section-header">WORK EXPERIENCE</div>
${workHTML}
<div class="section-header">EDUCATION</div>
${eduHTML}
<div class="section-header">SKILLS</div>
${skillHTML}
${projectHTML ? `<div class="section-header">PROJECTS</div>${projectHTML}` : ''}
${certHTML.includes('skill-category') ? `<div class="section-header">CERTIFICATIONS</div>${certHTML}` : ''}
</body>
</html>`;
}

return {
  json: {
    finalResume: finalResume
  }
};

